<script setup>
const props = defineProps(['options']);
const { options } = toRefs(props);

const selected = inject('selected');

const salesServiceDepartmentMapRef = ref(null);

const onSelect = (event) => {
    if (!event.target.dataset.region) return;
    // if (!event.target.classList.contains('region')) return;

    selected.value = options.value.find(option => option.value == event.target.dataset.region);
}

onMounted(() => {
    watch(selected, value => {
        salesServiceDepartmentMapRef.value.querySelector('.active')?.classList.remove('active');
        salesServiceDepartmentMapRef.value.querySelector(`[data-region='${value?.value}']`)?.classList.add('active');
    });
})
</script>